const body = $input.first().json.body || {};
const mode = (body.mode || 'full').toLowerCase().trim();
const program_name = (body.program_name || '').toUpperCase().trim();

if (mode === 'single' && !program_name) {
  throw new Error('program_name es requerido cuando mode=single');
}

return { json: { mode, program_name } };

const items = $input.all();

const summary = {};
const totals = { pending: 0, stale: 0, completed: 0, in_progress: 0, failed: 0 };

for (const item of items) {
  const { scope, content_type, status, count } = item.json;
  const key = `${scope}/${content_type}`;
  if (!summary[key]) summary[key] = {};
  summary[key][status] = parseInt(count);
  if (totals[status] !== undefined) totals[status] += parseInt(count);
}

return {
  json: {
    success: true,
    message: 'Content status initialized/updated successfully',
    totals,
    detail: summary
  }
};
